// Verifies the GitHub webhook signature before anything else runs.
// GitHub signs the RAW request body with the webhook secret and sends it as
// X-Hub-Signature-256. Without this check, anyone who learns the webhook URL
// can trigger a production deploy.
//
// The Webhook node must have "Raw Body" enabled so we hash the exact bytes
// GitHub sent — re-stringifying parsed JSON does not reliably round-trip.

const crypto = require('crypto');

// Prefer an env var on the n8n host; otherwise paste the secret below.
let secret;
try { secret = $env.FHA_DEPLOY_SECRET; } catch (e) { secret = undefined; }
if (!secret) secret = 'REPLACE_WITH_WEBHOOK_SECRET';
if (!secret || secret === 'REPLACE_WITH_WEBHOOK_SECRET') {
  throw new Error('Deploy webhook secret is not configured in n8n.');
}

const item = $input.first();
const headers = item.json.headers || {};
const signature = headers['x-hub-signature-256'];
if (!signature) {
  throw new Error('Missing X-Hub-Signature-256 header - rejecting unsigned request.');
}

const bin = item.binary && item.binary.data;
if (!bin) {
  throw new Error('Raw body unavailable - enable "Raw Body" on the Webhook node.');
}
const raw = Buffer.from(bin.data, 'base64');

const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(raw).digest('hex');

// Constant-time comparison so we do not leak the signature via timing.
const a = Buffer.from(signature);
const b = Buffer.from(expected);
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Invalid webhook signature - rejecting request.');
}

return [{ json: { body: JSON.parse(raw.toString('utf8')), verified: true } }];
